"use client";

import {
  useCallback,
  useEffect,
  useMemo,
  useReducer,
  useRef,
  useState,
} from "react";
import type {
  Story,
  StoryItem,
  StoryViewerDelta,
  StoryViewerLocalAction,
  Subscribe,
} from "../types";

// ─── Pure helpers ────────────────────────────────────────────────────────────

function insertStoryAtPosition(
  state: Story[],
  story: Story,
  position: "start" | "end" | undefined,
): Story[] {
  if (position === "start") return [story, ...state];
  return [...state, story]; // default "end" — cursor-stable for ID-anchored cursor
}

function removeStoryById(state: Story[], id: string): Story[] {
  const next = state.filter((s) => s.id !== id);
  return next.length === state.length ? state : next;
}

function patchStoryById(
  state: Story[],
  id: string,
  patch: Partial<Story>,
): Story[] {
  let mutated = false;
  const next = state.map((s) => {
    if (s.id !== id) return s;
    mutated = true;
    return { ...s, ...patch };
  });
  return mutated ? next : state;
}

function addItemToStory(
  state: Story[],
  storyId: string,
  item: StoryItem,
  position: "start" | "end" | undefined,
): Story[] {
  let mutated = false;
  const next = state.map((s) => {
    if (s.id !== storyId) return s;
    mutated = true;
    const items = position === "start" ? [item, ...s.items] : [...s.items, item];
    return { ...s, items };
  });
  return mutated ? next : state;
}

function removeItemFromStory(
  state: Story[],
  storyId: string,
  itemId: string,
): Story[] {
  let mutated = false;
  const next = state.map((s) => {
    if (s.id !== storyId) return s;
    const items = s.items.filter((i) => i.id !== itemId);
    if (items.length === s.items.length) return s;
    mutated = true;
    return { ...s, items };
  });
  return mutated ? next : state;
}

// ─── Reducer ─────────────────────────────────────────────────────────────────

/** Pure reducer — exported for hosts driving their own state. */
export function storyViewerReducer(
  state: Story[],
  action: StoryViewerLocalAction,
): Story[] {
  switch (action.kind) {
    case "add-story":
      return insertStoryAtPosition(state, action.story, action.position);
    case "remove-story":
      return removeStoryById(state, action.storyId);
    case "add-item":
      return addItemToStory(state, action.storyId, action.item, action.position);
    case "remove-item":
      return removeItemFromStory(state, action.storyId, action.itemId);
    case "patch-story":
      return patchStoryById(state, action.storyId, action.partial);
    case "subscribe-delta": {
      const d = action.delta;
      switch (d.kind) {
        case "story-added":
          return insertStoryAtPosition(state, d.story, d.position);
        case "story-removed":
          return removeStoryById(state, d.storyId);
        case "item-added":
          return addItemToStory(state, d.storyId, d.item, d.position);
        case "item-removed":
          return removeItemFromStory(state, d.storyId, d.itemId);
        case "story-viewed":
          return patchStoryById(state, d.storyId, { hasUnread: false });
      }
      return state;
    }
    case "reset":
      return action.next;
  }
}

// ─── Internal cursor (ID-anchored) ──────────────────────────────────────────

interface CursorIds {
  storyId: string;
  itemId: string;
}

// ─── Hook ────────────────────────────────────────────────────────────────────

export interface UseStoryViewerStateOptions {
  /** Captured ON MOUNT only — subsequent prop changes are ignored. */
  initialStories: Story[];
  /** Re-seeds cursor whenever (initialStoryIndex, isOpen) pair changes. */
  initialStoryIndex: number;
  /** Re-seeds cursor whenever (initialStoryIndex, isOpen) pair changes. */
  isOpen: boolean;

  subscribe?: Subscribe<StoryViewerDelta>;
  onSubscribeDelta?: (delta: StoryViewerDelta) => void;

  onStoryViewed?: (storyId: string) => void;
  onItemViewed?: (storyId: string, itemId: string, itemIndex: number) => void;
  onCursorChange?: (storyIndex: number, itemIndex: number) => void;
  onAutoCloseAtEnd?: () => void;
  onClose: () => void;
}

export interface UseStoryViewerStateResult {
  stories: Story[];
  /** Public derived cursor (indices for caller; IDs are internal). */
  cursor: { storyIndex: number; itemIndex: number };
  isPaused: boolean;
  isMuted: boolean;
  setPaused: React.Dispatch<React.SetStateAction<boolean>>;
  setMuted: React.Dispatch<React.SetStateAction<boolean>>;
  goToPrevItem: () => void;
  goToNextItem: () => void;
  goToPrevStory: () => void;
  goToNextStory: () => void;
  goToStoryIndex: (index: number) => void;
  goToItemIndex: (index: number) => void;
  reset: (next: Story[]) => void;
  dispatch: React.Dispatch<StoryViewerLocalAction>;
}

export function useStoryViewerState(
  opts: UseStoryViewerStateOptions,
): UseStoryViewerStateResult {
  const {
    initialStories,
    initialStoryIndex,
    isOpen,
    subscribe,
    onSubscribeDelta,
    onStoryViewed,
    onItemViewed,
    onCursorChange,
    onAutoCloseAtEnd,
    onClose,
  } = opts;

  const [stories, dispatch] = useReducer(storyViewerReducer, initialStories);

  const initialStoriesRef = useRef(stories);
  useEffect(() => {
    initialStoriesRef.current = stories;
  });

  // Refs-mirror for callbacks so effect deps stay narrow.
  const onSubscribeDeltaRef = useRef(onSubscribeDelta);
  const onStoryViewedRef = useRef(onStoryViewed);
  const onItemViewedRef = useRef(onItemViewed);
  const onCursorChangeRef = useRef(onCursorChange);
  const onAutoCloseAtEndRef = useRef(onAutoCloseAtEnd);
  const onCloseRef = useRef(onClose);
  useEffect(() => {
    onSubscribeDeltaRef.current = onSubscribeDelta;
    onStoryViewedRef.current = onStoryViewed;
    onItemViewedRef.current = onItemViewed;
    onCursorChangeRef.current = onCursorChange;
    onAutoCloseAtEndRef.current = onAutoCloseAtEnd;
    onCloseRef.current = onClose;
  });

  // Subscribe wiring (mount-scoped; identity-stable per host convention).
  useEffect(() => {
    if (!subscribe) return;
    const unsub = subscribe((delta) => {
      onSubscribeDeltaRef.current?.(delta);
      dispatch({ kind: "subscribe-delta", delta });
    });
    return unsub;
  }, [subscribe]);

  // ─── Cursor state (ID-anchored) ───────────────────────────────────────────
  // Lazy initializer — runs once at mount, derived from props.
  const [cursorIds, setCursorIds] = useState<CursorIds>(() => {
    const idx = Math.max(0, Math.min(initialStoryIndex, initialStories.length - 1));
    const story = initialStories[idx];
    return {
      storyId: story?.id ?? "",
      itemId: story?.items[0]?.id ?? "",
    };
  });

  // Reset cursor when (initialStoryIndex, isOpen) pair changes.
  // Read stories from ref to keep deps narrow.
  useEffect(() => {
    if (!isOpen) return;
    const snap = initialStoriesRef.current;
    const idx = Math.max(0, Math.min(initialStoryIndex, snap.length - 1));
    const story = snap[idx];
    if (!story) return;
    setCursorIds({
      storyId: story.id,
      itemId: story.items[0]?.id ?? "",
    });
  }, [initialStoryIndex, isOpen]);

  // Derive indices from IDs.
  const cursor = useMemo(() => {
    const storyIndex = Math.max(0, stories.findIndex((s) => s.id === cursorIds.storyId));
    const story = stories[storyIndex];
    const itemIndex = story
      ? Math.max(0, story.items.findIndex((i) => i.id === cursorIds.itemId))
      : 0;
    return { storyIndex, itemIndex };
  }, [stories, cursorIds]);

  // Fire onCursorChange whenever derived indices change.
  const lastCursorRef = useRef(cursor);
  useEffect(() => {
    const last = lastCursorRef.current;
    if (last.storyIndex !== cursor.storyIndex || last.itemIndex !== cursor.itemIndex) {
      lastCursorRef.current = cursor;
      onCursorChangeRef.current?.(cursor.storyIndex, cursor.itemIndex);
    }
  }, [cursor]);

  // ─── Pause / mute ────────────────────────────────────────────────────────
  const [isPaused, setPaused] = useState(false);
  const [isMuted, setMuted] = useState(true);

  // Reset pause on item key change — React 19 pattern: setState during render
  // when a derived prop changes. Keeps resume from sticking after auto-advance.
  const itemKey = `${cursorIds.storyId}:${cursorIds.itemId}`;
  const [renderedItemKey, setRenderedItemKey] = useState(itemKey);
  if (renderedItemKey !== itemKey) {
    setRenderedItemKey(itemKey);
    setPaused(false);
  }

  // ─── Navigation helpers ──────────────────────────────────────────────────
  const goToPrevItem = useCallback(() => {
    const snap = initialStoriesRef.current;
    const sIdx = snap.findIndex((s) => s.id === cursorIds.storyId);
    if (sIdx < 0) return;
    const story = snap[sIdx];
    const iIdx = story.items.findIndex((i) => i.id === cursorIds.itemId);
    if (iIdx > 0) {
      setCursorIds({ storyId: story.id, itemId: story.items[iIdx - 1].id });
      return;
    }
    if (sIdx > 0) {
      const prevStory = snap[sIdx - 1];
      const lastItem = prevStory.items[prevStory.items.length - 1];
      if (lastItem) {
        setCursorIds({ storyId: prevStory.id, itemId: lastItem.id });
      }
    }
    // else: at the very start; no-op.
  }, [cursorIds]);

  const goToNextItem = useCallback(() => {
    const snap = initialStoriesRef.current;
    const sIdx = snap.findIndex((s) => s.id === cursorIds.storyId);
    if (sIdx < 0) return;
    const story = snap[sIdx];
    const iIdx = story.items.findIndex((i) => i.id === cursorIds.itemId);
    const item = story.items[iIdx];
    if (item) {
      onItemViewedRef.current?.(story.id, item.id, iIdx);
    }
    if (iIdx < story.items.length - 1) {
      setCursorIds({ storyId: story.id, itemId: story.items[iIdx + 1].id });
      return;
    }
    // At last item — advance to next story (forward).
    onStoryViewedRef.current?.(story.id);
    if (sIdx < snap.length - 1) {
      const nextStory = snap[sIdx + 1];
      const firstItem = nextStory.items[0];
      if (firstItem) {
        setCursorIds({ storyId: nextStory.id, itemId: firstItem.id });
        return;
      }
    }
    // No next story — auto-close.
    onAutoCloseAtEndRef.current?.();
    onCloseRef.current();
  }, [cursorIds]);

  const goToPrevStory = useCallback(() => {
    const snap = initialStoriesRef.current;
    const sIdx = snap.findIndex((s) => s.id === cursorIds.storyId);
    if (sIdx <= 0) return;
    const prevStory = snap[sIdx - 1];
    const firstItem = prevStory.items[0];
    if (firstItem) {
      // Backward — does NOT fire onStoryViewed.
      setCursorIds({ storyId: prevStory.id, itemId: firstItem.id });
    }
  }, [cursorIds]);

  const goToNextStory = useCallback(() => {
    const snap = initialStoriesRef.current;
    const sIdx = snap.findIndex((s) => s.id === cursorIds.storyId);
    if (sIdx < 0) return;
    const story = snap[sIdx];
    onStoryViewedRef.current?.(story.id);
    if (sIdx < snap.length - 1) {
      const nextStory = snap[sIdx + 1];
      const firstItem = nextStory.items[0];
      if (firstItem) {
        setCursorIds({ storyId: nextStory.id, itemId: firstItem.id });
        return;
      }
    }
    onAutoCloseAtEndRef.current?.();
    onCloseRef.current();
  }, [cursorIds]);

  const goToStoryIndex = useCallback((index: number) => {
    const snap = initialStoriesRef.current;
    const sIdx = Math.max(0, Math.min(index, snap.length - 1));
    const target = snap[sIdx];
    if (!target) return;
    const currentSIdx = snap.findIndex((s) => s.id === cursorIds.storyId);
    // Forward jump — fire onStoryViewed for the leaving story.
    if (sIdx > currentSIdx && currentSIdx >= 0) {
      onStoryViewedRef.current?.(snap[currentSIdx].id);
    }
    setCursorIds({
      storyId: target.id,
      itemId: target.items[0]?.id ?? "",
    });
  }, [cursorIds]);

  const goToItemIndex = useCallback((index: number) => {
    const snap = initialStoriesRef.current;
    const sIdx = snap.findIndex((s) => s.id === cursorIds.storyId);
    if (sIdx < 0) return;
    const story = snap[sIdx];
    const iIdx = Math.max(0, Math.min(index, story.items.length - 1));
    const item = story.items[iIdx];
    if (!item) return;
    setCursorIds({ storyId: story.id, itemId: item.id });
  }, [cursorIds]);

  const reset = useCallback((next: Story[]) => {
    dispatch({ kind: "reset", next });
  }, []);

  return {
    stories,
    cursor,
    isPaused,
    isMuted,
    setPaused,
    setMuted,
    goToPrevItem,
    goToNextItem,
    goToPrevStory,
    goToNextStory,
    goToStoryIndex,
    goToItemIndex,
    reset,
    dispatch,
  };
}

"use client";

import { useEffect, useRef, useState } from "react";

export interface UseStoryProgressOptions {
  /** Viewer is mounted-and-open. When false, timer is fully stopped. */
  isOpen: boolean;
  /** When true, the timer pauses but accumulator is preserved (resume continues from same %). */
  isPaused: boolean;
  /** Compound key — typically `${storyId}:${itemId}`. Any change resets the accumulator. */
  itemKey: string;
  /** Total item duration in milliseconds. */
  itemDurationMs: number;
  /** Fires once when progress reaches 100. */
  onComplete: () => void;
  /** Tick interval. Default 50ms. */
  tickMs?: number;
}

/**
 * Accumulator-based story progress timer.
 *
 * Tracks an `accumulatedMs` accumulator across pause/resume cycles so users
 * can pause for arbitrary durations without losing playback position.
 * Naive `Date.now() - startTime` recomputes (kasder's original pattern) silently
 * advance ~50ms per pause/resume cycle. Switched to `performance.now()` here
 * for monotonic clock + immunity to NTP / DST jumps.
 */
export function useStoryProgress({
  isOpen,
  isPaused,
  itemKey,
  itemDurationMs,
  onComplete,
  tickMs = 50,
}: UseStoryProgressOptions) {
  const [progress, setProgress] = useState(0);
  const [renderedItemKey, setRenderedItemKey] = useState(itemKey);
  const accumulatedRef = useRef(0);
  const startTimeRef = useRef<number | null>(null);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const completedRef = useRef(false);
  const onCompleteRef = useRef(onComplete);

  useEffect(() => {
    onCompleteRef.current = onComplete;
  });

  // Reset on item change — React 19 pattern: setState during render when
  // a derivable prop changes. Refs get reset in the effect below.
  if (renderedItemKey !== itemKey) {
    setRenderedItemKey(itemKey);
    setProgress(0);
  }

  // Refs reset on item change — runs before the timer effect (declaration order).
  useEffect(() => {
    accumulatedRef.current = 0;
    completedRef.current = false;
  }, [itemKey]);

  useEffect(() => {
    if (!isOpen) {
      // Fully stop on close.
      accumulatedRef.current = 0;
      startTimeRef.current = null;
      if (intervalRef.current !== null) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
      return;
    }

    if (isPaused) {
      // Snapshot elapsed into accumulator + clear interval.
      if (startTimeRef.current !== null) {
        accumulatedRef.current += performance.now() - startTimeRef.current;
        startTimeRef.current = null;
      }
      if (intervalRef.current !== null) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
      return;
    }

    // Run.
    startTimeRef.current = performance.now();
    intervalRef.current = setInterval(() => {
      const startedAt = startTimeRef.current;
      if (startedAt === null) return;
      const elapsed = performance.now() - startedAt + accumulatedRef.current;
      const pct = Math.min((elapsed / itemDurationMs) * 100, 100);
      setProgress(pct);
      if (pct >= 100 && !completedRef.current) {
        completedRef.current = true;
        accumulatedRef.current = 0;
        startTimeRef.current = null;
        if (intervalRef.current !== null) {
          clearInterval(intervalRef.current);
          intervalRef.current = null;
        }
        onCompleteRef.current();
      }
    }, tickMs);

    return () => {
      if (intervalRef.current !== null) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
    };
  }, [isOpen, isPaused, itemKey, itemDurationMs, tickMs]);

  return progress;
}

"use client";

import { useEffect, useRef } from "react";

export interface UseStoryKeyboardNavOptions {
  isOpen: boolean;
  onPrevItem: () => void;
  onNextItem: () => void;
  onTogglePause: () => void;
  /** Optional — Radix Dialog already handles Escape via `onOpenChange`; supply only if you want a parallel hook. */
  onClose?: () => void;
}

/**
 * Window-scoped keyboard handlers for the story viewer.
 *
 * - ArrowLeft → onPrevItem
 * - ArrowRight → onNextItem
 * - Space → onTogglePause (preventDefault to stop page scroll)
 * - Escape → onClose (when supplied; deduplicated with Radix Dialog)
 *
 * Listener attaches on `isOpen=true` only and detaches on close — no leaks.
 * Refs-mirror pattern keeps the listener stable; only re-attaches on `isOpen` flip.
 */
export function useStoryKeyboardNav(opts: UseStoryKeyboardNavOptions) {
  const refs = useRef(opts);
  useEffect(() => {
    refs.current = opts;
  });

  const { isOpen } = opts;
  useEffect(() => {
    if (!isOpen) return;
    const handler = (e: KeyboardEvent) => {
      switch (e.key) {
        case "ArrowLeft":
          refs.current.onPrevItem();
          break;
        case "ArrowRight":
          refs.current.onNextItem();
          break;
        case " ":
          e.preventDefault();
          refs.current.onTogglePause();
          break;
        case "Escape":
          refs.current.onClose?.();
          break;
      }
    };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, [isOpen]);
}

"use client";

import { useEffect, useReducer, useRef } from "react";
import type {
  StoryEngagementDelta,
  StoryEngagementLocalAction,
  Subscribe,
} from "../types";

// ─── Per-item engagement state ──────────────────────────────────────────

export interface StoryItemEngagementState {
  likeCount: number;
  liked: boolean;
  reactionCount: number;
  viewerReaction: string | null;
  replyCount: number;
}

const DEFAULT_STATE: StoryItemEngagementState = {
  likeCount: 0,
  liked: false,
  reactionCount: 0,
  viewerReaction: null,
  replyCount: 0,
};

/**
 * Compound key for the state map. Story-viewer-01's engagement state is
 * per-(storyId, itemId) — each item in each story tracks independently.
 */
function key(storyId: string, itemId: string): string {
  return `${storyId}:${itemId}`;
}

// ─── Reducer (pure) ─────────────────────────────────────────────────────

type EngagementStateMap = Record<string, StoryItemEngagementState>;

export function storyEngagementReducer(
  state: EngagementStateMap,
  action: StoryEngagementLocalAction,
): EngagementStateMap {
  switch (action.kind) {
    case "like-toggle": {
      const k = key(action.storyId, action.itemId);
      const prev = state[k] ?? DEFAULT_STATE;
      if (prev.liked === action.nextLiked) return state;
      return {
        ...state,
        [k]: {
          ...prev,
          liked: action.nextLiked,
          likeCount: action.nextLiked
            ? prev.likeCount + 1
            : Math.max(0, prev.likeCount - 1),
        },
      };
    }
    case "reaction-select": {
      const k = key(action.storyId, action.itemId);
      const prev = state[k] ?? DEFAULT_STATE;
      if (prev.viewerReaction === action.reactionKind) return state;
      // Clearing a reaction decrements; setting a new one (when none was set)
      // increments. Switching from one kind to another keeps the count stable.
      let nextCount = prev.reactionCount;
      if (action.reactionKind == null && prev.viewerReaction != null) {
        nextCount = Math.max(0, prev.reactionCount - 1);
      } else if (action.reactionKind != null && prev.viewerReaction == null) {
        nextCount = prev.reactionCount + 1;
      }
      return {
        ...state,
        [k]: {
          ...prev,
          viewerReaction: action.reactionKind,
          reactionCount: nextCount,
        },
      };
    }
    case "subscribe-delta": {
      const d = action.delta;
      switch (d.kind) {
        case "like-changed": {
          const k = key(d.storyId, d.itemId);
          const prev = state[k] ?? DEFAULT_STATE;
          return {
            ...state,
            [k]: {
              ...prev,
              likeCount: d.count,
              liked: d.liked ?? prev.liked,
            },
          };
        }
        case "reaction-changed": {
          const k = key(d.storyId, d.itemId);
          const prev = state[k] ?? DEFAULT_STATE;
          return {
            ...state,
            [k]: {
              ...prev,
              reactionCount: d.count,
              viewerReaction:
                d.reactionKind !== undefined ? d.reactionKind : prev.viewerReaction,
            },
          };
        }
        case "reply-added": {
          const k = key(d.storyId, d.itemId);
          const prev = state[k] ?? DEFAULT_STATE;
          return { ...state, [k]: { ...prev, replyCount: prev.replyCount + 1 } };
        }
        // viewer-added and view-count-changed don't affect per-item engagement
        // (they're owner-overlay concerns); ignored here, handled in OwnerOverlay.
        case "viewer-added":
        case "view-count-changed":
          return state;
      }
      return state;
    }
    case "reset": {
      const k = key(action.storyId, action.itemId);
      const { [k]: _drop, ...rest } = state;
      return rest;
    }
  }
}

// ─── Hook ────────────────────────────────────────────────────────────────

export interface UseStoryEngagementStateOptions {
  /** Wired engagementSubscribe stream from story-viewer-01 props. */
  subscribe?: Subscribe<StoryEngagementDelta>;
  /** Forwarding callback — fires for every delta the subscription emits. */
  onSubscribeDelta?: (delta: StoryEngagementDelta) => void;
}

export interface UseStoryEngagementStateResult {
  /** Reads per-(storyId, itemId) engagement state. Returns DEFAULT_STATE when no entry exists yet. */
  getState: (storyId: string, itemId: string) => StoryItemEngagementState;
  /** Dispatcher for local actions (used by overlay onToggle / onSelect). */
  dispatch: React.Dispatch<StoryEngagementLocalAction>;
}

/**
 * Per-(storyId, itemId) engagement state hook. Subscribes to the optional
 * engagement realtime stream + reduces local actions (like / reaction toggles)
 * into a single state map.
 *
 * Mount-scoped subscribe wiring (matches the rest of the family's contract).
 */
export function useStoryEngagementState(
  opts: UseStoryEngagementStateOptions,
): UseStoryEngagementStateResult {
  const [state, dispatch] = useReducer(storyEngagementReducer, {});

  const onSubscribeDeltaRef = useRef(opts.onSubscribeDelta);
  useEffect(() => {
    onSubscribeDeltaRef.current = opts.onSubscribeDelta;
  });

  const subscribe = opts.subscribe;
  useEffect(() => {
    if (!subscribe) return;
    const unsub = subscribe((delta) => {
      onSubscribeDeltaRef.current?.(delta);
      dispatch({ kind: "subscribe-delta", delta });
    });
    return unsub;
  }, [subscribe]);

  const getState = (storyId: string, itemId: string): StoryItemEngagementState =>
    state[key(storyId, itemId)] ?? DEFAULT_STATE;

  return { getState, dispatch };
}

export function defaultFormatTime(date: Date): string {
  return new Intl.DateTimeFormat(undefined, {
    hour: "2-digit",
    minute: "2-digit",
  }).format(date);
}

/**
 * Pure permission resolver for story-viewer-01 v0.2.0.
 *
 * Mirrors post-card-01 v0.3.0's `lib/permissions.ts` shape verbatim per
 * Q-V10 lock. Resolution order (most → least specific):
 *   1. `canPerformAction(action, story, item)` returning `true | false` — wins
 *   2. `permissions[canX]` per-field — `false` denies, `true` allows
 *   3. `viewerMode`-derived defaults from `PERMISSION_DEFAULTS_BY_MODE`
 *   4. Library-baseline default (legacy v0.1 mode — caller short-circuits before
 *      calling this resolver; see `lib/kebab.ts` dual-mode branch)
 *
 * Truth table (same shape as post-card-01):
 * | viewerMode  | permissions  | resolved matrix                                    |
 * |-------------|--------------|----------------------------------------------------|
 * | `undefined` | `undefined`  | (resolver NOT called — legacy v0.1 path)           |
 * | `undefined` | `{ ... }`    | viewer baseline + permissions override per-field   |
 * | `"owner"`   | `undefined`  | owner defaults                                     |
 * | `"owner"`   | `{ ... }`    | owner defaults + permissions override per-field    |
 * | `"viewer"`  | `undefined`  | viewer defaults                                    |
 * | `"viewer"`  | `{ ... }`    | viewer defaults + permissions override per-field   |
 */

import type {
  Story,
  StoryItem,
  StoryPermissionAction,
  StoryViewerMode,
  StoryViewerPermissions,
} from "../types";

/**
 * Library-baseline permission matrix by viewer mode. `Required<StoryViewerPermissions>`
 * ensures every field is resolved (no `undefined` leaks downstream).
 *
 * `canShare` defaults to `true` in BOTH modes (owners share their own; viewers
 * share other people's). `canModerate` defaults to `false` in BOTH — orthogonal
 * capability, never auto-derived from `viewerMode` (per Q-V11 lock — host opts
 * in explicitly via `permissions.canModerate: true` or `canPerformAction`).
 */
export const PERMISSION_DEFAULTS_BY_MODE: Record<
  StoryViewerMode,
  Required<StoryViewerPermissions>
> = {
  owner: {
    // owner-side affordances
    canSaveToHighlights: true,
    canDeleteStory: true,
    canShareToFeed: true,
    canSeeViewers: true,
    // viewer-side off for owners (they don't react to their own story)
    canReact: false,
    canReply: false,
    canShare: true,
    canDM: false,
    canReport: false,
    canBlockAuthor: false,
    canMuteAuthor: false,
    // moderation is orthogonal to viewerMode — never auto-derived
    canModerate: false,
  },
  viewer: {
    // owner-side off for viewers
    canSaveToHighlights: false,
    canDeleteStory: false,
    canShareToFeed: false,
    canSeeViewers: false,
    // viewer-side full
    canReact: true,
    canReply: true,
    canShare: true,
    canDM: true,
    canReport: true,
    canBlockAuthor: true,
    canMuteAuthor: true,
    canModerate: false,
  },
};

/**
 * Special-case map for action discriminator keys that don't auto-capitalize
 * cleanly. `dm` → `canDM` (DM as an acronym; not `canDm`). All other actions
 * use the generic `can${cap(action)}` pattern.
 */
const SPECIAL_KEYS: Partial<Record<StoryPermissionAction, keyof StoryViewerPermissions>> = {
  dm: "canDM",
};

/**
 * Map a `StoryPermissionAction` string to its `StoryViewerPermissions` matrix key.
 *
 * `"saveToHighlights"` → `"canSaveToHighlights"`, `"react"` → `"canReact"`, etc.
 * `"dm"` → `"canDM"` via SPECIAL_KEYS (preserves acronym casing).
 * Pure, no side effects.
 */
function actionToPermissionKey(
  action: StoryPermissionAction,
): keyof StoryViewerPermissions {
  if (action in SPECIAL_KEYS) return SPECIAL_KEYS[action]!;
  return `can${action.charAt(0).toUpperCase()}${action.slice(1)}` as keyof StoryViewerPermissions;
}

/**
 * Pure resolver — returns the fully-resolved permission matrix for the
 * rendering pass. Does NOT consult `canPerformAction` (that's evaluated
 * per-action by `canPerformStoryActionInternal`).
 *
 * Caller's contract: only invoke when role-aware mode is active (at least one
 * of `viewerMode` / `permissions` / `canPerformAction` is set). Legacy mode
 * short-circuits in the calling helper before this is reached.
 */
export function resolveStoryPermissions(
  viewerMode: StoryViewerMode | undefined,
  permissions: StoryViewerPermissions | undefined,
): Required<StoryViewerPermissions> {
  const base = viewerMode
    ? PERMISSION_DEFAULTS_BY_MODE[viewerMode]
    : PERMISSION_DEFAULTS_BY_MODE.viewer; // viewer baseline when viewerMode undefined but permissions set
  if (!permissions) return { ...base };
  // Skip undefined fields during merge: `permissions={{ canReact: undefined }}`
  // should fall through to the mode default, not override it with undefined.
  const result: Required<StoryViewerPermissions> = { ...base };
  for (const key of Object.keys(permissions) as (keyof StoryViewerPermissions)[]) {
    const value = permissions[key];
    if (value !== undefined) {
      result[key] = value;
    }
  }
  return result;
}

/**
 * Per-action resolution. Returns `true` to allow the action / `false` to deny.
 *
 * Resolution:
 *   1. `canPerformAction(action, story, item)` returning `true | false` wins
 *   2. Matrix value from `resolvedMatrix` (already includes mode defaults +
 *      permissions overrides)
 *
 * `canPerformAction` returning `undefined` falls through to step 2.
 */
export function canPerformStoryActionInternal(
  action: StoryPermissionAction,
  story: Story,
  item: StoryItem,
  resolvedMatrix: Required<StoryViewerPermissions>,
  canPerformAction:
    | ((action: StoryPermissionAction, story: Story, item: StoryItem) => boolean | undefined)
    | undefined,
): boolean {
  if (canPerformAction) {
    const result = canPerformAction(action, story, item);
    if (result !== undefined) return result;
  }
  return resolvedMatrix[actionToPermissionKey(action)] !== false;
}

/**
 * Build the StoryEngagementAction[] for the engagement overlay's
 * <EngagementBar01 variant="stacked">. Honors the resolved permissions matrix
 * + reactionKinds + per-item engagement state.
 *
 * Reaction action is only added when both `canReact` resolves true AND the
 * host supplied `reactionKinds` (per Q-V4 lock — engagement-bar v0.3.x reaction
 * kinds are host-supplied, no library defaults).
 */

import type {
  Story,
  StoryEngagementAction,
  StoryEngagementReactionKind,
  StoryItem,
  StoryPermissionAction,
  StoryViewerPermissions,
} from "../types";
import type { StoryItemEngagementState } from "../hooks/use-story-engagement-state";
import {
  canPerformStoryActionInternal,
  resolveStoryPermissions,
} from "./permissions";

export interface BuildEngagementActionsOptions {
  story: Story;
  item: StoryItem;
  state: StoryItemEngagementState;
  /** Resolved matrix from resolveStoryPermissions. */
  matrix: Required<StoryViewerPermissions>;
  canPerformAction?: (
    action: StoryPermissionAction,
    story: Story,
    item: StoryItem,
  ) => boolean | undefined;
  reactionKinds?: StoryEngagementReactionKind[];
  /** Like toggle handler — fires onLikeStory through to the consumer. */
  onLikeToggle?: (nextLiked: boolean) => void;
  /** Reaction select handler — fires onReactStory. */
  onReactSelect?: (kind: string | null) => void;
  /** Comment click handler — typically focuses the reply composer. */
  onCommentClick?: () => void;
  /** Share click handler. */
  onShareClick?: () => void;
  /** Bookmark toggle handler. */
  onBookmarkToggle?: (next: boolean) => void;
  /** Initial bookmark state (host-supplied via Story/StoryItem extension or kept local). */
  isBookmarked?: boolean;
  /** Kebab open handler — fires when the 6th custom-action is tapped. */
  onKebabOpen?: () => void;
  /** Icon node for the kebab custom action. */
  kebabIcon?: import("react").ReactNode;
  /** Aria label for the kebab custom action. */
  kebabLabel?: string;
}

export function buildStoryEngagementActions(
  opts: BuildEngagementActionsOptions,
): StoryEngagementAction[] {
  const canDo = (action: StoryPermissionAction) =>
    canPerformStoryActionInternal(
      action,
      opts.story,
      opts.item,
      opts.matrix,
      opts.canPerformAction,
    );

  const actions: StoryEngagementAction[] = [];

  // Like (gated by canReact for viewer mode; owners don't like their own — matrix handles it)
  if (canDo("react")) {
    actions.push({
      kind: "like",
      count: opts.state.likeCount,
      liked: opts.state.liked,
      onToggle: opts.onLikeToggle,
    });
  }

  // Reaction — only when canReact AND reactionKinds supplied
  if (canDo("react") && opts.reactionKinds && opts.reactionKinds.length > 0) {
    actions.push({
      kind: "reaction",
      kinds: opts.reactionKinds,
      viewerReaction: opts.state.viewerReaction,
      onSelect: opts.onReactSelect,
      clearOnTap: true, // Q-V4 lock — inherited engagement-bar v0.3 default
    });
  }

  // Comment (always shown in viewer mode; opens reply composer)
  if (canDo("reply")) {
    actions.push({
      kind: "comment",
      count: opts.state.replyCount > 0 ? opts.state.replyCount : undefined,
      onClick: opts.onCommentClick,
    });
  }

  // Share
  if (canDo("share")) {
    actions.push({
      kind: "share",
      onClick: opts.onShareClick,
    });
  }

  // Bookmark (always available — no canBookmark in matrix; matches engagement-bar default)
  actions.push({
    kind: "bookmark",
    bookmarked: opts.isBookmarked ?? false,
    onToggle: opts.onBookmarkToggle,
  });

  // Kebab — last item, rendered via kind="custom" (Q-V17 lock — kebab in
  // engagement overlay as 6th item; HeaderKebabFallback handles disableEngagement).
  if (opts.onKebabOpen) {
    actions.push({
      kind: "custom",
      id: "kebab",
      label: opts.kebabLabel ?? "More",
      icon: opts.kebabIcon,
      onClick: opts.onKebabOpen,
    });
  }

  return actions;
}

/**
 * Convenience wrapper — resolves permissions matrix + builds the actions in
 * one call. Used by story-viewer-01.tsx when assembling the overlay.
 */
export function buildStoryEngagementActionsWithMatrix(
  opts: Omit<BuildEngagementActionsOptions, "matrix"> & {
    viewerMode?: "owner" | "viewer";
    permissions?: StoryViewerPermissions;
  },
): StoryEngagementAction[] {
  const matrix = resolveStoryPermissions(opts.viewerMode, opts.permissions);
  return buildStoryEngagementActions({ ...opts, matrix });
}

