"use client";

import { memo, useCallback, useRef } from "react";
import { cn } from "@/lib/utils";
// F-S1 cross-cat component import — absolute-with-suffix preserves through
// the shadcn 4.6.0 rewriter (Bug 3 only affects /types).
import {
  CommentComposer,
  type CommentComposerHandle,
} from "@/registry/components/data/comment-thread-01/parts/comment-composer";
import type {
  ResolvedStoryViewer01Labels,
  Story,
  StoryCurrentUser,
  StoryItem,
} from "../types";

export interface ReplyComposerProps {
  story: Story;
  item: StoryItem;
  /** Viewer identity — required for composer mount. Absent → composer hidden. */
  currentUser?: StoryCurrentUser;
  /** Submit handler — story-viewer-01 forwards via onAddReply prop. */
  onAddReply?: (storyId: string, itemId: string, content: string) => Promise<void> | void;
  /** Pause the story while user types; resume on submit/cancel. */
  onSetPaused: (paused: boolean) => void;
  labels: ResolvedStoryViewer01Labels;
  className?: string;
  /** Optional handle ref so the parent can focus / pre-fill the composer (triggerReply). */
  composerRef?: React.Ref<CommentComposerHandle>;
}

/**
 * Reply composer mounted at the bottom of the viewer per Q-V1 lock (always-
 * visible Instagram-default bottom bar). Auto-pauses the story timer on
 * first character; resumes on submit / cancel.
 *
 * Mounting gated by `viewerMode === "viewer"` AND `!disableReplyComposer` AND
 * `currentUser` present — caller handles those gates. This part trusts the
 * caller's decision.
 *
 * When `currentUser` is absent, the part returns null — story-viewer-01.tsx
 * mounts `composerEmptyState` slot instead (sign-in CTA for unauth viewers).
 */
function ReplyComposerInner(props: ReplyComposerProps) {
  // Track whether user has typed anything since last submit/cancel; auto-pause
  // fires only on the FIRST keystroke (cheap idempotent setPaused call too).
  const pausedRef = useRef(false);

  const handleChange = useCallback(
    (value: string) => {
      if (value.length > 0 && !pausedRef.current) {
        pausedRef.current = true;
        props.onSetPaused(true);
      } else if (value.length === 0 && pausedRef.current) {
        // User cleared the composer manually — resume the story.
        pausedRef.current = false;
        props.onSetPaused(false);
      }
    },
    [props.onSetPaused],
  );

  const handleSubmit = useCallback(
    async (content: string) => {
      try {
        await props.onAddReply?.(props.story.id, props.item.id, content);
      } finally {
        pausedRef.current = false;
        props.onSetPaused(false);
      }
    },
    [props.onAddReply, props.story.id, props.item.id, props.onSetPaused],
  );

  const handleCancel = useCallback(() => {
    pausedRef.current = false;
    props.onSetPaused(false);
  }, [props.onSetPaused]);

  if (!props.currentUser) return null;

  // CommentComposer accepts a stricter currentUser shape (CommentThreadCurrentUser).
  // StoryCurrentUser is structurally identical — cast at the boundary.
  return (
    <div
      className={cn(
        "absolute left-0 right-0 bottom-0 z-30 px-4 pb-4 pt-8",
        "bg-linear-to-t from-black/60 via-black/40 to-transparent",
        props.className,
      )}
    >
      <CommentComposer
        ref={props.composerRef}
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        currentUser={props.currentUser as any}
        placeholder={props.labels.replyComposerPlaceholder(props.story)}
        onChange={handleChange}
        onSubmit={handleSubmit}
        onCancel={handleCancel}
        submitOnEnter
        minRows={1}
        maxRows={3}
        ariaLabel={`Reply to ${props.story.username}`}
        labels={
          props.labels.commentLabels
            ? {
                composerPlaceholder: props.labels.commentLabels.composerPlaceholder,
                composerSend: props.labels.commentLabels.composerSend ?? props.labels.replyComposerSend,
                composerCancel: props.labels.commentLabels.composerCancel ?? props.labels.replyComposerCancel,
              }
            : {
                composerSend: props.labels.replyComposerSend,
                composerCancel: props.labels.replyComposerCancel,
              }
        }
      />
    </div>
  );
}

export const ReplyComposer = memo(ReplyComposerInner);
ReplyComposer.displayName = "ReplyComposer";

"use client";

import { memo, useCallback, useEffect, useState } from "react";
import { Eye, X } from "lucide-react";
import { cn } from "@/lib/utils";
import { buttonVariants } from "@/components/ui/button";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import type {
  ResolvedStoryViewer01Labels,
  Story,
  StoryItem,
  ViewerListItem,
} from "../types";

export interface OwnerOverlayProps {
  story: Story;
  item: StoryItem;
  /**
   * Lazy-fetch viewers when owner taps the view-count chip. Returns
   * ViewerListItem[]. Called once per panel-open; result cached locally.
   */
  onLoadViewers?: (storyId: string) => Promise<ViewerListItem[]>;
  labels: ResolvedStoryViewer01Labels;
  className?: string;
}

function initials(name: string): string {
  return (
    name
      .trim()
      .split(/\s+/)
      .map((part) => part[0]?.toUpperCase() ?? "")
      .slice(0, 2)
      .join("") || "?"
  );
}

/**
 * Owner overlay — bottom-anchored view-count chip + tap-to-expand viewers
 * list panel. Mounts only when `viewerMode === "owner"` + `!disableOwnerOverlay`.
 *
 * Per Q-V5 hybrid lock: count is eager (cheap byte from `story.viewerCount`),
 * users list is lazy (fetched on first tap via `onLoadViewers`). Optional
 * eager seed via `story.viewers` short-circuits the fetch.
 *
 * The expanded panel renders avatars + names inline (a simple list — not the
 * cross-cat LikersStrip — to keep the F-S1 surface minimal; LikersStrip can
 * be wired via `renderOwnerOverlay` slot if the host wants the swipable
 * variant).
 */
function OwnerOverlayInner(props: OwnerOverlayProps) {
  const eagerCount = props.story.viewerCount ?? props.story.viewers?.length ?? 0;
  const [open, setOpen] = useState(false);
  const [viewers, setViewers] = useState<ViewerListItem[]>(props.story.viewers ?? []);
  const [loading, setLoading] = useState(false);
  const [didFetch, setDidFetch] = useState(false);

  // Reset panel state when story changes (cursor navigation).
  useEffect(() => {
    setOpen(false);
    setViewers(props.story.viewers ?? []);
    setDidFetch(false);
  }, [props.story.id]);

  const handleToggle = useCallback(async () => {
    if (open) {
      setOpen(false);
      return;
    }
    setOpen(true);
    if (viewers.length === 0 && props.onLoadViewers && !loading && !didFetch) {
      setLoading(true);
      try {
        const list = await props.onLoadViewers(props.story.id);
        setViewers(list);
        setDidFetch(true);
      } catch {
        // Swallow; host can re-attempt via re-tap. No retry-with-backoff for v0.2.0.
      } finally {
        setLoading(false);
      }
    }
  }, [open, viewers.length, loading, didFetch, props.onLoadViewers, props.story.id]);

  const timeStr = props.labels.formatTime(new Date(props.story.createdAt));
  const ariaLabel = props.labels.viewerCountLabel(eagerCount, timeStr);

  return (
    <>
      {/* View-count chip — bottom-left of viewer (replaces reply composer in owner mode). */}
      <div
        className={cn(
          "absolute left-0 right-0 bottom-0 z-30 flex items-center px-4 pb-4 pt-8",
          "bg-linear-to-t from-black/60 via-black/40 to-transparent",
          props.className,
        )}
      >
        <button
          type="button"
          onClick={handleToggle}
          className={cn(
            buttonVariants({ variant: "ghost", size: "sm" }),
            "h-11 text-white hover:bg-white/20 hover:text-white",
          )}
          aria-label={ariaLabel}
          aria-expanded={open}
        >
          <Eye className="mr-2 h-4 w-4" />
          <span className="font-semibold">{eagerCount}</span>
          <span className="ml-2 text-white/70">· {timeStr}</span>
        </button>
      </div>

      {/* Viewers panel — bottom-anchored sheet that slides up. */}
      {open ? (
        <div className="absolute inset-x-0 bottom-0 z-40 max-h-[60%] overflow-hidden rounded-t-2xl bg-card text-foreground shadow-2xl">
          <div className="flex items-center justify-between border-b border-border px-4 py-3">
            <h3 className="text-sm font-semibold">{props.labels.viewersHeading}</h3>
            <button
              type="button"
              onClick={() => setOpen(false)}
              className={cn(
                buttonVariants({ variant: "ghost", size: "icon" }),
                "h-9 w-9",
              )}
              aria-label={props.labels.close}
            >
              <X className="h-4 w-4" />
            </button>
          </div>
          <div className="max-h-[50vh] overflow-y-auto">
            {loading ? (
              <p className="px-4 py-6 text-center text-sm text-muted-foreground">
                Loading viewers…
              </p>
            ) : viewers.length === 0 ? (
              <p className="px-4 py-6 text-center text-sm text-muted-foreground">
                No viewers yet.
              </p>
            ) : (
              <ul className="flex flex-col">
                {viewers.map((viewer) => (
                  <li
                    key={viewer.id}
                    className="flex items-center gap-3 border-b border-border/30 px-4 py-2 last:border-b-0"
                  >
                    <Avatar className="h-8 w-8 shrink-0">
                      {viewer.avatar ? <AvatarImage src={viewer.avatar} alt="" /> : null}
                      <AvatarFallback className="text-xs">{initials(viewer.name)}</AvatarFallback>
                    </Avatar>
                    <span className="flex-1 text-sm font-medium">{viewer.name}</span>
                    {viewer.viewedAt ? (
                      <span className="text-xs text-muted-foreground">
                        {props.labels.formatTime(new Date(viewer.viewedAt))}
                      </span>
                    ) : null}
                  </li>
                ))}
              </ul>
            )}
          </div>
        </div>
      ) : null}
    </>
  );
}

export const OwnerOverlay = memo(OwnerOverlayInner);
OwnerOverlay.displayName = "OwnerOverlay";

"use client";

import { Fragment, memo, useEffect } from "react";
import { X } from "lucide-react";
import { cn } from "@/lib/utils";
import { buttonVariants } from "@/components/ui/button";
import type {
  ResolvedStoryViewer01Labels,
  StoryKebabMenuItem,
} from "../types";

export interface KebabPanelProps {
  open: boolean;
  items: StoryKebabMenuItem[];
  onClose: () => void;
  labels: ResolvedStoryViewer01Labels;
  className?: string;
}

/**
 * Bottom-sheet action panel used by BOTH kebab placements:
 *
 *   - Engagement-overlay placement (default): triggered by the 6th custom
 *     action in the stacked engagement-bar (Q-V17 lock — Instagram-2024 exact).
 *   - Header fallback (disableEngagement=true): triggered by a button in the
 *     header right cluster.
 *
 * Renders as a fixed-position bottom sheet rather than a DropdownMenu — this
 * matches Instagram / Snapchat / TikTok action-sheet UX AND avoids the
 * F-cross-13 `<DropdownMenuTrigger asChild>{<Button>}` rewriter trap entirely.
 *
 * Items honor `separatorBefore: true` for the moderator section visual break.
 * Destructive items get `text-destructive` styling.
 *
 * Closes on item click + on backdrop tap + on Escape (handled at parent via
 * onClose dispatch).
 */
function KebabPanelInner(props: KebabPanelProps) {
  // Escape key handler — closes the panel when open.
  useEffect(() => {
    if (!props.open) return;
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") props.onClose();
    };
    window.addEventListener("keydown", handleKey);
    return () => window.removeEventListener("keydown", handleKey);
  }, [props.open, props.onClose]);

  if (!props.open || props.items.length === 0) return null;

  return (
    <>
      {/* Backdrop — taps close the panel. Above engagement overlay, below the sheet. */}
      <button
        type="button"
        aria-hidden="true"
        tabIndex={-1}
        className="absolute inset-0 z-40 cursor-default bg-black/40"
        onClick={props.onClose}
      />
      {/* Action sheet — bottom-anchored. */}
      <div
        role="menu"
        aria-label={props.labels.kebabAriaLabel}
        className={cn(
          "absolute inset-x-0 bottom-0 z-50 max-h-[70%] overflow-y-auto rounded-t-2xl bg-card text-foreground shadow-2xl",
          props.className,
        )}
      >
        <div className="flex items-center justify-between border-b border-border px-4 py-3">
          <span className="text-sm font-semibold">{props.labels.kebabAriaLabel}</span>
          <button
            type="button"
            onClick={props.onClose}
            className={cn(
              buttonVariants({ variant: "ghost", size: "icon" }),
              "h-9 w-9",
            )}
            aria-label={props.labels.close}
          >
            <X className="h-4 w-4" />
          </button>
        </div>
        <ul className="flex flex-col py-2">
          {props.items.map((item, i) => (
            <Fragment key={`${item.label}-${i}`}>
              {item.separatorBefore && i > 0 ? (
                <li role="separator" className="my-2 border-t border-border" aria-hidden="true" />
              ) : null}
              <li>
                <button
                  type="button"
                  role="menuitem"
                  disabled={item.disabled}
                  onClick={() => {
                    item.onClick?.();
                    props.onClose();
                  }}
                  className={cn(
                    "flex w-full items-center gap-3 px-4 py-3 text-left text-sm transition-colors",
                    "hover:bg-muted focus:bg-muted focus:outline-none",
                    "disabled:opacity-50 disabled:pointer-events-none",
                    item.destructive && "text-destructive hover:bg-destructive/10 focus:bg-destructive/10",
                  )}
                >
                  {item.icon ? <span className="shrink-0">{item.icon}</span> : null}
                  <span className="flex-1">{item.label}</span>
                </button>
              </li>
            </Fragment>
          ))}
        </ul>
      </div>
    </>
  );
}

export const KebabPanel = memo(KebabPanelInner);
KebabPanel.displayName = "KebabPanel";

/**
 * Default story kebab items builder. Dual-mode helper mirroring
 * post-card-01 v0.3.0's `defaultPostKebabActions`:
 *
 *   - **Legacy mode (v0.1 compat):** when `viewerMode` / `permissions` /
 *     `canPerformAction` are ALL undefined, returns []. Kebab is not rendered
 *     in legacy mode (v0.1 story viewer had no kebab).
 *
 *   - **Role-aware mode (v0.2.0):** when ANY of the three role-aware args is
 *     set, the helper calls `resolveStoryPermissions` +
 *     `canPerformStoryActionInternal` to produce role-appropriate items per
 *     the resolution order in `lib/permissions.ts`.
 *
 * Owner mode: Save to highlights / Delete story / Share to feed / Copy link.
 * Viewer mode: Copy link / Mute author / Block author / Report (destructive
 * at end).
 * Moderator section: only when `canModerate` resolves true + `moderatorActions`
 * supplied. First moderator item carries `separatorBefore: true`.
 *
 * `kebabActions` full-takeover bypasses this entirely (handled in story-viewer-01.tsx
 * before this is called).
 */

import type { ReactNode } from "react";
import type {
  Story,
  StoryItem,
  StoryKebabMenuItem,
  StoryPermissionAction,
  StoryViewer01Labels,
  StoryViewerMode,
  StoryViewerPermissions,
} from "../types";
import {
  canPerformStoryActionInternal,
  resolveStoryPermissions,
} from "./permissions";

export interface DefaultStoryKebabHandlers {
  /** Owner-side: save story to highlights. */
  onSaveToHighlights?: (storyId: string) => void;
  /** Owner-side: delete story. */
  onDeleteStory?: (storyId: string) => void;
  /** Owner-side: share to feed. */
  onShareToFeed?: (storyId: string) => void;
  /** Viewer-side: report. */
  onReport?: (storyId: string) => void;
  /** Viewer-side: block author. */
  onBlockAuthor?: (authorId: string) => void;
  /** Viewer-side: mute author. */
  onMuteAuthor?: (authorId: string) => void;
  /** Common: copy link to the story. */
  onCopyLink?: (storyId: string) => void;
  /** Whether the story is currently saved to highlights (toggles label). */
  isSavedToHighlights?: boolean;
}

export interface BuildStoryKebabActionsOptions {
  story: Story;
  item: StoryItem;
  handlers: DefaultStoryKebabHandlers;
  labels: Partial<
    Pick<
      Required<StoryViewer01Labels>,
      | "saveToHighlights"
      | "unsaveFromHighlights"
      | "deleteStory"
      | "shareToFeed"
      | "report"
      | "blockAuthor"
      | "muteAuthor"
      | "copyLink"
    >
  >;
  viewerMode?: StoryViewerMode;
  permissions?: StoryViewerPermissions;
  canPerformAction?: (
    action: StoryPermissionAction,
    story: Story,
    item: StoryItem,
  ) => boolean | undefined;
  /** Optional moderator section supplier (additive — does NOT replace defaults). */
  moderatorActions?: (story: Story, item: StoryItem) => StoryKebabMenuItem[];
  /** Optional icons for each canonical action (host can override). */
  icons?: Partial<Record<
    | "saveToHighlights"
    | "deleteStory"
    | "shareToFeed"
    | "copyLink"
    | "muteAuthor"
    | "blockAuthor"
    | "report",
    ReactNode
  >>;
}

export function defaultStoryKebabActions(
  opts: BuildStoryKebabActionsOptions,
): StoryKebabMenuItem[] {
  const roleAwareMode =
    opts.viewerMode !== undefined ||
    opts.permissions !== undefined ||
    opts.canPerformAction !== undefined;

  // Legacy mode — no kebab in v0.1. Return empty.
  if (!roleAwareMode) return [];

  const matrix = resolveStoryPermissions(opts.viewerMode, opts.permissions);
  const canDo = (action: StoryPermissionAction) =>
    canPerformStoryActionInternal(action, opts.story, opts.item, matrix, opts.canPerformAction);

  const items: StoryKebabMenuItem[] = [];

  // ─── Owner-side items ─────────────────────────────────────────────────
  if (canDo("saveToHighlights") && opts.handlers.onSaveToHighlights) {
    items.push({
      label: opts.handlers.isSavedToHighlights
        ? (opts.labels.unsaveFromHighlights ?? "Remove from highlights")
        : (opts.labels.saveToHighlights ?? "Save to highlights"),
      icon: opts.icons?.saveToHighlights,
      onClick: () => opts.handlers.onSaveToHighlights!(opts.story.id),
    });
  }
  if (canDo("shareToFeed") && opts.handlers.onShareToFeed) {
    items.push({
      label: opts.labels.shareToFeed ?? "Share to feed",
      icon: opts.icons?.shareToFeed,
      onClick: () => opts.handlers.onShareToFeed!(opts.story.id),
    });
  }

  // ─── Common items ─────────────────────────────────────────────────────
  if (opts.handlers.onCopyLink) {
    items.push({
      label: opts.labels.copyLink ?? "Copy link",
      icon: opts.icons?.copyLink,
      onClick: () => opts.handlers.onCopyLink!(opts.story.id),
    });
  }

  // ─── Moderator section (additive; gated by canModerate + moderatorActions) ──
  if (canDo("moderate") && opts.moderatorActions) {
    const modItems = opts.moderatorActions(opts.story, opts.item);
    if (modItems.length > 0) {
      // First moderator item carries `separatorBefore: true` (visual section break).
      items.push({ ...modItems[0], separatorBefore: true });
      for (let i = 1; i < modItems.length; i++) {
        items.push(modItems[i]);
      }
    }
  }

  // ─── Viewer-side items (destructive at the bottom) ───────────────────
  if (canDo("muteAuthor") && opts.handlers.onMuteAuthor) {
    items.push({
      label: opts.labels.muteAuthor ?? "Mute author",
      icon: opts.icons?.muteAuthor,
      onClick: () => opts.handlers.onMuteAuthor!(opts.story.userId),
    });
  }
  if (canDo("blockAuthor") && opts.handlers.onBlockAuthor) {
    items.push({
      label: opts.labels.blockAuthor ?? "Block author",
      icon: opts.icons?.blockAuthor,
      destructive: true,
      onClick: () => opts.handlers.onBlockAuthor!(opts.story.userId),
    });
  }
  if (canDo("report") && opts.handlers.onReport) {
    items.push({
      label: opts.labels.report ?? "Report",
      icon: opts.icons?.report,
      destructive: true,
      onClick: () => opts.handlers.onReport!(opts.story.id),
    });
  }

  // ─── Owner destructive (Delete — always last) ─────────────────────────
  if (canDo("deleteStory") && opts.handlers.onDeleteStory) {
    items.push({
      label: opts.labels.deleteStory ?? "Delete story",
      icon: opts.icons?.deleteStory,
      destructive: true,
      onClick: () => opts.handlers.onDeleteStory!(opts.story.id),
    });
  }

  return items;
}
